From iris.program_logic Require Import weakestpre.
From iris.proofmode Require Import proofmode.
From iris.base_logic.lib Require Import invariants.

From Stdlib Require Import Lia.

Require Import Syntax Helpers Typing Subtyping Bigstep DerivedCache.
Require Import PICOBridge.PicoMemoryModel PICOBridge.PicoCacheTyping.
Require Import PICOBridge.PicoIrisLanguage PICOBridge.PicoIrisSemanticCache PICOBridge.PicoIrisCacheInvariant.
Require Import PICOBridge.PicoIrisGhostState PICOBridge.PicoIrisStateInterp PICOBridge.PicoIrisStateBridge.
Require Import PICOBridge.PicoIrisThreadSafety PICOBridge.PicoIrisWPStateBridge PICOBridge.PicoIrisSemanticTyping.
Require Import Core.GenericCacheProtocol Iris.GenericCacheGhostState.
Require Import Core.GenericDerivedCache Iris.GenericDerivedCacheIris.

(** * Logical-Relation Facade for the PICO Iris Pipeline

    The current semantic interpretation is still the cache-safe interpretation
    from [PicoIrisSemanticTyping].  This file deliberately gives that
    interpretation logical-relation-facing names and exports the theorem
    boundaries that later ghost-state work should preserve.

    In other words, this is not yet the final type-indexed Iris logical
    relation.  It is the documented facade showing where such a logical
    relation will plug into the already-proved cache-safety pipeline. *)

Section pico_iris_logical_relation.
  Context `{Hmem : CacheMemoryModel}.
  Context (CT : class_table).
  Context `{!irisGS_gen hlc (pico_language CT) Σ}.

(** Value interpretation used by the current facade: integers and null are
    trivially valid; object references must have a runtime type compatible with
    the expected PICO type and qualifier context. *)
  Definition pico_lr_value
      (sigma : wm_state) (qcontext : q_r) (T : qualified_type)
      (v : Syntax.value) : Prop :=
    match v with
    | Null_a => True
    | Int _ => True
    | Iot loc =>
        exists rt,
          wm_get_type sigma loc = Some rt /\
          base_subtype CT (rctype rt) (sctype T) /\
          qualifier_typable_context (rqtype rt) (sqtype T) qcontext
    end.

  Definition pico_lr_valueI
      (sigma : wm_state) (qcontext : q_r) (T : qualified_type)
      (v : Syntax.value) : iProp Σ :=
    ⌜pico_lr_value sigma qcontext T v⌝%I.

(** Runtime environments satisfy a static environment when each runtime value
    satisfies [pico_lr_value] at the corresponding static type. *)
  Definition pico_lr_env
      (sigma : wm_state) (qcontext : q_r)
      (sΓ : s_env) (rΓ : r_env) : Prop :=
    List.length sΓ = List.length (vars rΓ) /\
    forall i T v,
      nth_error sΓ i = Some T ->
      runtime_getVal rΓ i = Some v ->
      pico_lr_value sigma qcontext T v.

  Definition pico_lr_envI
      (sigma : wm_state) (qcontext : q_r)
      (sΓ : s_env) (rΓ : r_env) : iProp Σ :=
    ⌜pico_lr_env sigma qcontext sΓ rΓ⌝%I.

  Definition pico_lr_expr_interp
      (sigma : wm_state) (qcontext : q_r)
      (sΓ : s_env) (rΓ : r_env) (mt : method_type)
      (e : expr) (T : qualified_type) (v : Syntax.value) : Prop :=
    expr_has_type CT sΓ mt e T /\
    pico_lr_value sigma qcontext T v.

  Definition pico_lr_exprI
      (sigma : wm_state) (qcontext : q_r)
      (sΓ : s_env) (rΓ : r_env) (mt : method_type)
      (e : expr) (T : qualified_type) (v : Syntax.value) : iProp Σ :=
    ⌜expr_has_type CT sΓ mt e T⌝ ∗ pico_lr_valueI sigma qcontext T v.

  Definition pico_lr_thread_step_envI
      (sigma : wm_state) (qcontext : q_r) (sΓ : s_env)
      (e : wm_thread) (sigma' : wm_state) (sΓ' : s_env)
      (e' : wm_thread) : iProp Σ :=
    pico_lr_envI sigma qcontext sΓ (wt_env e) -∗
    pico_lr_envI sigma' qcontext sΓ' (wt_env e').

  Definition pico_lr_thread_step_env_interp
      (sigma : wm_state) (qcontext : q_r) (sΓ : s_env)
      (e : wm_thread) (sigma' : wm_state) (sΓ' : s_env)
      (e' : wm_thread) : Prop :=
    pico_lr_env sigma qcontext sΓ (wt_env e) ->
    pico_lr_env sigma' qcontext sΓ' (wt_env e').

(** Statement interpretation currently packages ordinary PICO statement typing
    with semantic cache safety for the target cache field. *)
  Definition pico_lr_stmt_interp
      (sΓ sΓ' : s_env) (mt : method_type) (rΓ : r_env) (s : stmt)
      (addr : FieldAddr) (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : Prop :=
    stmt_typing CT sΓ mt s sΓ' /\
    cache_safe_stmt rΓ addr derived abs_vals s.

  Definition pico_lr_thread_interp
      (sΓ sΓ' : s_env) (mt : method_type) (e : wm_thread)
      (addr : FieldAddr) (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : Prop :=
    pico_lr_stmt_interp
      sΓ sΓ' mt (wt_env e) (wt_stmt e) addr derived abs_vals.

  Definition pico_lr_method_body_interp
      (sΓ sΓ' : s_env) (mt : method_type) (rΓ : r_env)
      (body : method_body) (addr : FieldAddr)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : Prop :=
    pico_lr_stmt_interp
      sΓ sΓ' mt rΓ (mbody_stmt body) addr derived abs_vals.

  Definition pico_lr_stmtI
      (sΓ sΓ' : s_env) (mt : method_type) (rΓ : r_env) (s : stmt)
      (addr : FieldAddr) (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    pico_sem_typed_stmt_cacheI CT sΓ sΓ' mt rΓ s addr derived abs_vals.

  Definition pico_lr_threadI
      (sΓ sΓ' : s_env) (mt : method_type) (e : wm_thread)
      (addr : FieldAddr) (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    pico_sem_typed_thread_cacheI CT sΓ sΓ' mt e addr derived abs_vals.

  Definition pico_lr_typed_threadI
      (sigma : wm_state) (qcontext : q_r)
      (sΓ sΓ' : s_env) (mt : method_type) (e : wm_thread)
      (addr : FieldAddr) (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    pico_lr_threadI sΓ sΓ' mt e addr derived abs_vals ∗
    pico_lr_envI sigma qcontext sΓ (wt_env e).

  Definition pico_lr_typed_thread_step_envI
      (sigma sigma' : wm_state) (qcontext : q_r)
      (sΓ sΓ' : s_env) (mt : method_type)
      (e e' : wm_thread) (addr : FieldAddr)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    pico_lr_typed_threadI
      sigma qcontext sΓ sΓ' mt e addr derived abs_vals ∗
    pico_lr_thread_step_envI sigma qcontext sΓ e sigma' sΓ' e'.

  Definition pico_lr_typed_thread_step_resultI
      (sigma' : wm_state) (qcontext : q_r)
      (sΓ sΓ' : s_env) (mt : method_type)
      (e e' : wm_thread) (addr : FieldAddr)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    pico_lr_threadI sΓ sΓ' mt e addr derived abs_vals ∗
    pico_lr_envI sigma' qcontext sΓ' (wt_env e').

(** Config-level LR facade is the semantic typed-cache config interpretation. *)
  Definition pico_lr_configI
      (cfg : wm_config) (addr : FieldAddr)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    pico_sem_typed_config_cacheI CT cfg addr derived abs_vals.

  Definition pico_lr_config_nth_typed_thread_step_envI
      (cfg : wm_config) (i : nat) (e : wm_thread)
      (sigma sigma' : wm_state) (e' : wm_thread)
      (qcontext : q_r) (addr : FieldAddr)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    pico_lr_configI cfg addr derived abs_vals ∗
    ⌜nth_error (wc_threads cfg) i = Some e⌝ ∗
    ∃ sΓ sΓ' mt,
      pico_lr_typed_thread_step_envI
        sigma sigma' qcontext sΓ sΓ' mt e e' addr derived abs_vals.

  Definition pico_lr_config_nth_typed_thread_step_resultI
      (cfg : wm_config) (i : nat) (e : wm_thread)
      (sigma' : wm_state) (e' : wm_thread)
      (qcontext : q_r) (addr : FieldAddr)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    ⌜nth_error (wc_threads cfg) i = Some e⌝ ∗
    ∃ sΓ sΓ' mt,
      pico_lr_typed_thread_step_resultI
        sigma' qcontext sΓ sΓ' mt e e' addr derived abs_vals.

(** LR-facing wrapper for the concrete cache-update sequence rule. *)
  Definition pico_lr_cache_update_sequenceI
      (sΓ : s_env) (mt : method_type) (rΓ : r_env)
      (loc : Loc) (cache_f receiver tmp : var)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) (n : nat) : iProp Σ :=
    pico_sem_cache_update_sequenceI
      CT sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n.

  Definition pico_lr_cache_compute_then_write_phasesI
      (sΓ sΓ_mid : s_env) (mt : method_type)
      (rΓ rΓ_mid : r_env) (loc : Loc)
      (cache_f receiver tmp : var) (compute : stmt)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    pico_sem_cache_compute_then_write_phasesI
      CT sΓ sΓ_mid mt rΓ rΓ_mid loc cache_f receiver tmp compute
      derived abs_vals.

  Definition pico_lr_cache_update_selected_first_executionI
      (rΓ : r_env) (receiver tmp cache_f : var) (n V : nat)
      (sigma : wm_state) (threads : list wm_thread) (i : nat)
      (cfg' : wm_config) : iProp Σ :=
    ⌜cache_update_sequence_selected_first_execution
      CT rΓ receiver tmp cache_f n V sigma threads i cfg'⌝%I.

  Definition pico_lr_thread_entry
      (addr : FieldAddr) (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) (e : wm_thread) : Prop :=
    sem_typed_thread_entry CT addr derived abs_vals e.

  Definition pico_lr_config_entries
      (cfg : wm_config) (addr : FieldAddr)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : Prop :=
    Forall (pico_lr_thread_entry addr derived abs_vals) (wc_threads cfg).

  Definition pico_lr_method_bodyI
      (sΓ sΓ' : s_env) (mt : method_type) (rΓ : r_env)
      (body : method_body) (addr : FieldAddr)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    pico_lr_stmtI sΓ sΓ' mt rΓ (mbody_stmt body) addr derived abs_vals.

  Definition pico_lr_config_interp
      (addr : FieldAddr) (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) (cfg : wm_config) : Prop :=
    sem_typed_config_entry_interpretation CT addr derived abs_vals cfg.

  Definition pico_lr_config_step_closure
      (addr : FieldAddr) (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : Prop :=
    forall c1 c2,
      wm_step CT c1 c2 ->
      pico_lr_config_interp addr derived abs_vals c1 ->
      pico_lr_config_interp addr derived abs_vals c2.

  Definition pico_lr_config_step_closureI
      (addr : FieldAddr) (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    ⌜pico_lr_config_step_closure addr derived abs_vals⌝%I.

  Definition pico_lr_cache_compute_then_write_phases_tail_execution_specI
      (sΓ sΓ_mid : s_env) (mt : method_type)
      (rΓ rΓ_mid : r_env) (loc : Loc)
      (cache_f receiver tmp : var) (compute : stmt)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) (V : nat)
      (sigma : wm_state) (cfg' : wm_config) : iProp Σ :=
    let tail_cfg :=
      mkWMConfig
        sigma
        [mkWMThread rΓ_mid (SFldWrite receiver cache_f tmp) V] in
    ⌜wm_steps CT tail_cfg cfg' /\
      wm_config_cache_history_state tail_cfg (loc, cache_f) derived abs_vals⌝ ∗
    pico_lr_cache_compute_then_write_phasesI
      sΓ sΓ_mid mt rΓ rΓ_mid loc cache_f receiver tmp compute
      derived abs_vals ∗
    pico_lr_config_step_closureI (loc, cache_f) derived abs_vals.

  Definition pico_lr_cache_compute_then_write_phases_tail_read_specI
      (sΓ sΓ_mid : s_env) (mt : method_type)
      (rΓ rΓ_mid : r_env) (loc : Loc)
      (cache_f receiver tmp : var) (compute : stmt)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) (V : nat)
      (sigma : wm_state) (cfg' : wm_config)
      (Vread : view) (v : Syntax.value) (Vread' : view) : iProp Σ :=
    pico_lr_cache_compute_then_write_phases_tail_execution_specI
      sΓ sΓ_mid mt rΓ rΓ_mid loc cache_f receiver tmp compute
      derived abs_vals V sigma cfg' ∗
    ⌜wm_read (wc_state cfg') Vread (loc, cache_f) v Vread'⌝.

  Definition pico_lr_cache_update_sequence_tail_execution_specI
      (sΓ : s_env) (mt : method_type) (rΓ : r_env)
      (loc : Loc) (cache_f receiver tmp : var)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) (n V : nat)
      (sigma : wm_state) (cfg' : wm_config) : iProp Σ :=
    let rΓ_mid := set_vars rΓ (update tmp (Int n) (vars rΓ)) in
    let tail_cfg :=
      mkWMConfig
        sigma
        [mkWMThread rΓ_mid (SFldWrite receiver cache_f tmp) V] in
    ⌜wm_steps CT tail_cfg cfg' /\
      wm_config_cache_history_state tail_cfg (loc, cache_f) derived abs_vals⌝ ∗
    pico_lr_cache_update_sequenceI
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n ∗
    pico_lr_config_step_closureI (loc, cache_f) derived abs_vals.

  Definition pico_lr_cache_update_sequence_tail_read_specI
      (sΓ : s_env) (mt : method_type) (rΓ : r_env)
      (loc : Loc) (cache_f receiver tmp : var)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) (n V : nat)
      (sigma : wm_state) (cfg' : wm_config)
      (Vread : view) (v : Syntax.value) (Vread' : view) : iProp Σ :=
    pico_lr_cache_update_sequence_tail_execution_specI
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n V sigma cfg' ∗
    ⌜wm_read (wc_state cfg') Vread (loc, cache_f) v Vread'⌝.

  Definition pico_lr_config_prefix_interp
      (addr : FieldAddr) (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : Prop :=
    forall c1 c2,
      wm_step CT c1 c2 ->
      pico_lr_config_interp addr derived abs_vals c1.

  Definition pico_lr_config_prefix_interpI
      (addr : FieldAddr) (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    ⌜pico_lr_config_prefix_interp addr derived abs_vals⌝%I.

  Definition pico_lr_config_execution_prefix_interp
      (cfg cfg' : wm_config) (addr : FieldAddr)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : Prop :=
    forall c1 c2,
      wm_steps CT cfg c1 ->
      wm_step CT c1 c2 ->
      wm_steps CT c2 cfg' ->
      pico_lr_config_interp addr derived abs_vals c1.

  Definition pico_lr_config_execution_prefix_interpI
      (cfg cfg' : wm_config) (addr : FieldAddr)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    ⌜pico_lr_config_execution_prefix_interp cfg cfg' addr derived abs_vals⌝%I.

  Definition pico_lr_config_execution_prefix_read_specI
      (cfg cfg' : wm_config) (V : view) (addr : FieldAddr)
      (v : Syntax.value) (V' : view)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    ⌜wm_steps CT cfg cfg' /\
      wm_config_cache_history_state cfg addr derived abs_vals /\
      wm_read (wc_state cfg') V addr v V'⌝ ∗
    pico_lr_config_execution_prefix_interpI cfg cfg' addr derived abs_vals.

  Definition pico_lr_cache_update_execution_evidenceI
      (rΓ : r_env) (receiver tmp cache_f : var) (n V : nat)
      (sigma : wm_state) (threads : list wm_thread) (i : nat)
      (cfg' : wm_config) (addr : FieldAddr)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    pico_lr_cache_update_selected_first_executionI
      rΓ receiver tmp cache_f n V sigma threads i cfg' ∗
    pico_lr_config_step_closureI addr derived abs_vals.

  Definition pico_lr_cache_update_execution_specI
      (sΓ : s_env) (mt : method_type) (rΓ : r_env)
      (loc : Loc) (cache_f receiver tmp : var)
      (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) (n V : nat)
      (sigma : wm_state) (threads : list wm_thread) (i : nat)
      (cfg' : wm_config) : iProp Σ :=
    pico_lr_cache_update_sequenceI
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n ∗
    pico_lr_configI
      (mkWMConfig sigma threads)
      (loc, cache_f)
      derived
      abs_vals ∗
    wm_config_cache_history_stateI
      (mkWMConfig sigma threads)
      (loc, cache_f)
      derived
      abs_vals ∗
    ⌜nth_error
      threads
      i =
      Some
        (mkWMThread
          rΓ
          (cache_update_sequence_stmt tmp receiver cache_f n)
          V)⌝ ∗
    pico_lr_cache_update_execution_evidenceI
      rΓ receiver tmp cache_f n V sigma threads i cfg'
      (loc, cache_f) derived abs_vals.

  Definition pico_lr_thread_post_stepsI
      (addr : FieldAddr) (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    ⌜forall c1 c2,
      wm_step CT c1 c2 ->
      forall sigma sigma' threads i t t',
        c1 = mkWMConfig sigma threads ->
        nth_error threads i = Some t ->
        wm_thread_step CT sigma t sigma' t' ->
        pico_lr_thread_entry addr derived abs_vals t'⌝%I.

  Lemma pico_lr_thread_entry_assign_int_post :
    forall addr derived abs_vals rΓ V x n old_v,
      pico_lr_thread_entry
        addr derived abs_vals
        (mkWMThread rΓ (SVarAss x (EInt n)) V) ->
      runtime_getVal rΓ x = Some old_v ->
      pico_lr_thread_entry
        addr derived abs_vals
        (mkWMThread
          (set_vars rΓ (update x (Int n) (vars rΓ)))
          SSkip
          V).
  Proof.
    intros addr derived abs_vals rΓ V x n old_v Hentry Hruntime.
    unfold pico_lr_thread_entry in *.
    eapply sem_typed_thread_entry_assign_int_post; eauto.
  Qed.

  Lemma pico_lr_thread_entry_field_read_post :
    forall addr derived abs_vals sigma rΓ V V' x y f loc_y v,
      pico_lr_thread_entry
        addr derived abs_vals
        (mkWMThread rΓ (SVarAss x (EField y f)) V) ->
      runtime_getVal rΓ y = Some (Iot loc_y) ->
      wm_read sigma V (loc_y, f) v V' ->
      pico_lr_thread_entry
        addr derived abs_vals
        (mkWMThread
          (set_vars rΓ (update x v (vars rΓ)))
          SSkip
          V').
  Proof.
    intros addr derived abs_vals sigma rΓ V V' x y f loc_y v
           Hentry Hruntime Hread.
    unfold pico_lr_thread_entry in *.
    eapply sem_typed_thread_entry_field_read_post; eauto.
  Qed.

  Lemma pico_lr_thread_entry_fldwrite_post :
    forall addr derived abs_vals rΓ V V' x f y,
      pico_lr_thread_entry
        addr derived abs_vals
        (mkWMThread rΓ (SFldWrite x f y) V) ->
      pico_lr_thread_entry
        addr derived abs_vals
        (mkWMThread rΓ SSkip V').
  Proof.
    intros addr derived abs_vals rΓ V V' x f y Hentry.
    unfold pico_lr_thread_entry in *.
    eapply sem_typed_thread_entry_fldwrite_post; eauto.
  Qed.

  Lemma pico_lr_thread_entry_seqskip_post :
    forall addr derived abs_vals rΓ V s2,
      pico_lr_thread_entry
        addr derived abs_vals
        (mkWMThread rΓ (SSeq SSkip s2) V) ->
      pico_lr_thread_entry
        addr derived abs_vals
        (mkWMThread rΓ s2 V).
  Proof.
    intros addr derived abs_vals rΓ V s2 Hentry.
    unfold pico_lr_thread_entry in *.
    eapply sem_typed_thread_entry_seqskip_post; eauto.
  Qed.

  Lemma pico_lr_thread_entry_seqstep_residual_post :
    forall addr derived abs_vals sΓ sΓ_mid sΓ'' mt
      rΓ' V' s1' s2,
      stmt_typing CT sΓ mt s1' sΓ_mid ->
      stmt_typing CT sΓ_mid mt s2 sΓ'' ->
      cache_safe_thread
        (mkWMThread rΓ' s1' V') addr derived abs_vals ->
      cache_safe_thread
        (mkWMThread rΓ' s2 V') addr derived abs_vals ->
      pico_lr_thread_entry
        addr derived abs_vals
        (mkWMThread rΓ' (residual_seq_wm s1' s2) V').
  Proof.
    intros addr derived abs_vals sΓ sΓ_mid sΓ'' mt
           rΓ' V' s1' s2 Htype1 Htype2 Hsafe1 Hsafe2.
    unfold pico_lr_thread_entry.
    eapply sem_typed_thread_entry_seqstep_residual_post; eauto.
  Qed.

  Lemma pico_lr_thread_entry_seqstep_assign_int_post :
    forall addr derived abs_vals rΓ V x n old_v s2,
      pico_lr_thread_entry
        addr derived abs_vals
        (mkWMThread rΓ (SSeq (SVarAss x (EInt n)) s2) V) ->
      runtime_getVal rΓ x = Some old_v ->
      cache_safe_thread
        (mkWMThread
          (set_vars rΓ (update x (Int n) (vars rΓ)))
          s2
          V)
        addr
        derived
        abs_vals ->
      pico_lr_thread_entry
        addr derived abs_vals
        (mkWMThread
          (set_vars rΓ (update x (Int n) (vars rΓ)))
          s2
          V).
  Proof.
    intros addr derived abs_vals rΓ V x n old_v s2
           Hentry Hruntime Hsafe2.
    unfold pico_lr_thread_entry in *.
    eapply sem_typed_thread_entry_seqstep_assign_int_post; eauto.
  Qed.

  Lemma pico_lr_thread_entry_seqstep_field_read_post :
    forall addr derived abs_vals sigma rΓ V V' x y f loc_y v s2,
      pico_lr_thread_entry
        addr derived abs_vals
        (mkWMThread rΓ (SSeq (SVarAss x (EField y f)) s2) V) ->
      runtime_getVal rΓ y = Some (Iot loc_y) ->
      wm_read sigma V (loc_y, f) v V' ->
      cache_safe_thread
        (mkWMThread
          (set_vars rΓ (update x v (vars rΓ)))
          s2
          V')
        addr
        derived
        abs_vals ->
      pico_lr_thread_entry
        addr derived abs_vals
        (mkWMThread
          (set_vars rΓ (update x v (vars rΓ)))
          s2
          V').
  Proof.
    intros addr derived abs_vals sigma rΓ V V' x y f loc_y v s2
           Hentry Hruntime Hread Hsafe2.
    unfold pico_lr_thread_entry in *.
    eapply sem_typed_thread_entry_seqstep_field_read_post; eauto.
  Qed.

  Lemma pico_lr_thread_entry_seqstep_fldwrite_post :
    forall addr derived abs_vals rΓ V V' x f y s2,
      pico_lr_thread_entry
        addr derived abs_vals
        (mkWMThread rΓ (SSeq (SFldWrite x f y) s2) V) ->
      cache_safe_thread
        (mkWMThread rΓ s2 V')
        addr
        derived
        abs_vals ->
      pico_lr_thread_entry
        addr derived abs_vals
        (mkWMThread rΓ s2 V').
  Proof.
    intros addr derived abs_vals rΓ V V' x f y s2 Hentry Hsafe2.
    unfold pico_lr_thread_entry in *.
    eapply sem_typed_thread_entry_seqstep_fldwrite_post; eauto.
  Qed.

  Lemma pico_lr_valueI_intro :
    forall sigma qcontext T v,
      pico_lr_value sigma qcontext T v ->
      ⊢ pico_lr_valueI sigma qcontext T v.
  Proof.
    intros sigma qcontext T v Hval.
    iPureIntro.
    exact Hval.
  Qed.

  Lemma pico_lr_valueI_elim :
    forall sigma qcontext T v,
      pico_lr_valueI sigma qcontext T v -∗
      ⌜pico_lr_value sigma qcontext T v⌝.
  Proof.
    iIntros (sigma qcontext T v) "Hval".
    iExact "Hval".
  Qed.

  Lemma pico_lr_nullI :
    forall sigma qcontext T,
      ⊢ pico_lr_valueI sigma qcontext T Null_a.
  Proof.
    intros sigma qcontext T.
    iPureIntro.
    simpl.
    exact I.
  Qed.

  Lemma pico_lr_intI :
    forall sigma qcontext T n,
      ⊢ pico_lr_valueI sigma qcontext T (Int n).
  Proof.
    intros sigma qcontext T n.
    iPureIntro.
    simpl.
    exact I.
  Qed.

  Lemma pico_lr_objectI :
    forall sigma qcontext T loc rt,
      wm_get_type sigma loc = Some rt ->
      base_subtype CT (rctype rt) (sctype T) ->
      qualifier_typable_context (rqtype rt) (sqtype T) qcontext ->
      ⊢ pico_lr_valueI sigma qcontext T (Iot loc).
  Proof.
    intros sigma qcontext T loc rt Htype Hbase Hqual.
    iPureIntro.
    exists rt.
    repeat split; assumption.
  Qed.

  Lemma pico_lr_envI_intro :
    forall sigma qcontext sΓ rΓ,
      pico_lr_env sigma qcontext sΓ rΓ ->
      ⊢ pico_lr_envI sigma qcontext sΓ rΓ.
  Proof.
    intros sigma qcontext sΓ rΓ Henv.
    iPureIntro.
    exact Henv.
  Qed.

  Lemma pico_lr_envI_elim :
    forall sigma qcontext sΓ rΓ,
      pico_lr_envI sigma qcontext sΓ rΓ -∗
      ⌜pico_lr_env sigma qcontext sΓ rΓ⌝.
  Proof.
    iIntros (sigma qcontext sΓ rΓ) "Henv".
    iExact "Henv".
  Qed.

  Lemma pico_lr_envI_lookup :
    forall sigma qcontext sΓ rΓ i T v,
      nth_error sΓ i = Some T ->
      runtime_getVal rΓ i = Some v ->
      pico_lr_envI sigma qcontext sΓ rΓ -∗
      pico_lr_valueI sigma qcontext T v.
  Proof.
    iIntros (sigma qcontext sΓ rΓ i T v Hstatic Hruntime) "Henv".
    iDestruct "Henv" as %[Hlen Hlookup].
    iPureIntro.
    eapply Hlookup; eauto.
  Qed.

  Lemma pico_lr_env_local_null :
    forall sigma qcontext sΓ rΓ T,
      pico_lr_env sigma qcontext sΓ rΓ ->
      pico_lr_env
        sigma
        qcontext
        (sΓ ++ [T])
        (set_vars rΓ (vars rΓ ++ [Null_a])).
  Proof.
    intros sigma qcontext sΓ rΓ T [Hlen Hlookup].
    split.
    - simpl.
      rewrite !length_app.
      simpl.
      lia.
    - intros i Ti v Hstatic Hruntime.
      unfold runtime_getVal in Hruntime.
      simpl in Hruntime.
      destruct (lt_dec i (length sΓ)) as [Hlt | Hge].
      + rewrite nth_error_app1 in Hstatic; [|exact Hlt].
        rewrite nth_error_app1 in Hruntime; [|lia].
        eapply Hlookup; eauto.
      + rewrite nth_error_app2 in Hstatic; [|lia].
        assert (i - length sΓ = 0) as Hidx.
        {
          assert (i - length sΓ < length [T]) as Hidx_lt.
          {
            eapply nth_error_Some.
            rewrite Hstatic.
            discriminate.
          }
          simpl in Hidx_lt.
          lia.
        }
        rewrite Hidx in Hstatic.
        inversion Hstatic; subst.
        rewrite nth_error_app2 in Hruntime; [|lia].
        assert (i - length (vars rΓ) = 0) as Hidx_runtime by lia.
        rewrite Hidx_runtime in Hruntime.
        inversion Hruntime; subst.
        simpl.
        exact I.
  Qed.

  Lemma pico_lr_envI_local_null :
    forall sigma qcontext sΓ rΓ T,
      pico_lr_envI sigma qcontext sΓ rΓ -∗
      pico_lr_envI
        sigma
        qcontext
        (sΓ ++ [T])
        (set_vars rΓ (vars rΓ ++ [Null_a])).
  Proof.
    iIntros (sigma qcontext sΓ rΓ T) "Henv".
    iDestruct "Henv" as "%Henv".
    iPureIntro.
    eapply pico_lr_env_local_null; eauto.
  Qed.

  Lemma pico_lr_env_update :
    forall sigma qcontext sΓ rΓ x T v,
      pico_lr_env sigma qcontext sΓ rΓ ->
      nth_error sΓ x = Some T ->
      pico_lr_value sigma qcontext T v ->
      pico_lr_env
        sigma
        qcontext
        sΓ
        (set_vars rΓ (update x v (vars rΓ))).
  Proof.
    intros sigma qcontext sΓ rΓ x T v [Hlen Hlookup] Hstatic_x Hval.
    split.
    - simpl.
      rewrite update_length.
      exact Hlen.
    - intros i Ti vi Hstatic_i Hruntime_i.
      unfold runtime_getVal in Hruntime_i.
      simpl in Hruntime_i.
      destruct (Nat.eq_dec i x) as [Heq | Hneq].
      + subst i.
        assert (Ti = T) by congruence.
        subst Ti.
        assert (x < length (vars rΓ)).
        {
          rewrite <- Hlen.
          eapply nth_error_Some.
          rewrite Hstatic_x.
          discriminate.
        }
        rewrite update_same in Hruntime_i; [|exact H].
        inversion Hruntime_i; subst.
        exact Hval.
      + rewrite update_diff in Hruntime_i.
        eapply Hlookup; eauto.
        intro Heq.
        apply Hneq.
        symmetry.
        exact Heq.
  Qed.

  Lemma pico_lr_envI_update :
    forall sigma qcontext sΓ rΓ x T v,
      nth_error sΓ x = Some T ->
      pico_lr_valueI sigma qcontext T v -∗
      pico_lr_envI sigma qcontext sΓ rΓ -∗
      pico_lr_envI
        sigma
        qcontext
        sΓ
        (set_vars rΓ (update x v (vars rΓ))).
  Proof.
    iIntros (sigma qcontext sΓ rΓ x T v Hstatic_x) "Hval Henv".
    iDestruct "Hval" as "%Hval".
    iDestruct "Henv" as "%Henv".
    iPureIntro.
    eapply pico_lr_env_update; eauto.
  Qed.

  Lemma pico_lr_value_subtype :
    forall sigma qcontext T1 T2 v,
      qualified_type_subtype CT T1 T2 ->
      pico_lr_value sigma qcontext T1 v ->
      pico_lr_value sigma qcontext T2 v.
  Proof.
    intros sigma qcontext T1 T2 v Hsub Hval.
    destruct v as [|loc|n]; simpl in *; auto.
    destruct Hval as [rt [Htype [Hbase Hqual]]].
    exists rt.
    split; [exact Htype |].
    split.
    - eapply base_trans; eauto.
      eapply qualified_type_subtype_base_subtype; eauto.
    - eapply qualifier_typable_subtype; eauto.
  Qed.

  Lemma pico_lr_valueI_subtype :
    forall sigma qcontext T1 T2 v,
      qualified_type_subtype CT T1 T2 ->
      pico_lr_valueI sigma qcontext T1 v -∗
      pico_lr_valueI sigma qcontext T2 v.
  Proof.
    iIntros (sigma qcontext T1 T2 v Hsub) "Hval".
    iDestruct "Hval" as "%Hval".
    iPureIntro.
    eapply pico_lr_value_subtype; eauto.
  Qed.

  Lemma pico_lr_envI_update_subtype :
    forall sigma qcontext sΓ rΓ x T1 T2 v,
      nth_error sΓ x = Some T2 ->
      qualified_type_subtype CT T1 T2 ->
      pico_lr_valueI sigma qcontext T1 v -∗
      pico_lr_envI sigma qcontext sΓ rΓ -∗
      pico_lr_envI
        sigma
        qcontext
        sΓ
        (set_vars rΓ (update x v (vars rΓ))).
  Proof.
    iIntros (sigma qcontext sΓ rΓ x T1 T2 v Hstatic Hsub)
      "Hval Henv".
    iApply (pico_lr_envI_update with "[Hval] Henv").
    - exact Hstatic.
    - iApply (pico_lr_valueI_subtype with "Hval").
      exact Hsub.
  Qed.

  Lemma pico_lr_exprI_intro :
    forall sigma qcontext sΓ rΓ mt e T v,
