  Lemma pico_lr_field_read_thread_step_env_interp :
    forall sigma qcontext sΓ rΓ mt V V' x y f loc_y Te Tx v,
      runtime_getVal rΓ y = Some (Iot loc_y) ->
      wm_read sigma V (loc_y, f) v V' ->
      static_getType sΓ x = Some Tx ->
      qualified_type_subtype CT Te Tx ->
      expr_has_type CT sΓ mt (EField y f) Te ->
      pico_lr_expr_interp sigma qcontext sΓ rΓ mt (EField y f) Te v ->
      pico_lr_thread_step_env_interp
