  Lemma pico_lr_config_execution_prefix_from_closure :
    forall cfg cfg' addr derived abs_vals,
      wm_steps CT cfg cfg' ->
      pico_lr_config_interp addr derived abs_vals cfg ->
      pico_lr_config_step_closure addr derived abs_vals ->
      pico_lr_config_execution_prefix_interp cfg cfg' addr derived abs_vals.
  Proof.
    intros cfg cfg' addr derived abs_vals _ Hinterp Hclosed.
    assert (Hreach :
      forall c0 c1,
        wm_steps CT c0 c1 ->
        pico_lr_config_interp addr derived abs_vals c0 ->
        pico_lr_config_interp addr derived abs_vals c1).
    {
      intros c0 c1 Hsteps.
      induction Hsteps as [c | c0 c1 c2 Hstep Htail IH];
        intros Hc0.
      - exact Hc0.
      - apply IH.
        eapply Hclosed; eauto.
    }
    intros c1 c2 Hsteps_cfg_c1 _ _.
    eapply Hreach; eauto.
  Qed.

