      pico_lr_config_execution_prefix_interpI cfg cfg' addr derived abs_vals.
  Proof.
    iIntros (cfg cfg' addr derived abs_vals Hsteps) "Hcfg Hclosed".
    iDestruct (pico_lr_configI_interp with "Hcfg") as %Hinterp.
    iDestruct "Hclosed" as %Hclosed.
    iApply pico_lr_config_execution_prefix_interpI_intro.
    eapply pico_lr_config_execution_prefix_from_closure; eauto.
  Qed.

  Theorem pico_lr_config_execution_prefix_preserve_cache_history :
    forall cfg cfg' addr derived abs_vals,
      wm_steps CT cfg cfg' ->
      pico_lr_config_execution_prefix_interp cfg cfg' addr derived abs_vals ->
      wm_config_cache_history_state cfg addr derived abs_vals ->
      wm_config_cache_history_state cfg' addr derived abs_vals.
  Proof.
    intros cfg cfg' addr derived abs_vals Hsteps Hprefix Hstate.
    induction Hsteps as [cfg0 | cfg1 cfg2 cfg3 Hstep Htail IH].
    - exact Hstate.
    - apply IH.
      + intros c1 c2 Hsteps_cfg2_c1 Hstep_c1_c2 Hsteps_c2_cfg3.
        apply (Hprefix c1 c2).
        * eapply WMS_Step; eauto.
        * exact Hstep_c1_c2.
        * exact Hsteps_c2_cfg3.
      + eapply wm_step_preserves_cache_history; eauto.
        eapply wm_step_cache_safe_from_config_allowed; eauto.
        apply cache_safe_config_implies_wm_config_threads_allowed.
        apply pico_lr_config_interp_cache_safe_config.
        apply (Hprefix cfg1 cfg2).
        * apply WMS_Refl.
        * exact Hstep.
        * exact Htail.
  Qed.

