  Lemma wp_pico_lr_cache_update_sequence_with_tail
      s E Φ sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n V :
    cache_update_sequence_safe
      CT sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n ->
    let tail :=
      mkWMThread
        (set_vars rΓ (update tmp (Int n) (vars rΓ)))
        (SFldWrite receiver cache_f tmp)
        V in
    let full :=
      mkWMThread
        rΓ
        (cache_update_sequence_stmt tmp receiver cache_f n)
        V in
    (∀ sigma ns k ks nt,
      state_interp sigma ns (k ++ ks) nt ={E,∅}=∗
      ▷ (£ 1 ={∅,E}=∗
        state_interp sigma (S ns) ks nt ∗
        (pico_lr_threadI sΓ sΓ mt tail (loc, cache_f) derived abs_vals -∗
          WP tail @ s; E {{ Φ }})))
    ⊢ WP full @ s; E {{ Φ }}.
  Proof.
    simpl.
    iIntros (Hsafe) "Htail".
    iApply wp_pico_lift_cache_update_sequence_with_sem_typed_tail; [exact Hsafe |].
    iIntros (sigma ns k ks nt) "Hstate".
    iMod ("Htail" with "Hstate") as "Htail_step".
    iModIntro.
    iNext.
    iIntros "Hcred".
    iMod ("Htail_step" with "Hcred") as "[$ Hwp_from_lr]".
    iModIntro.
    iIntros "Hsem".
    iApply "Hwp_from_lr".
    unfold pico_lr_threadI.
    iExact "Hsem".
  Qed.

