  Lemma pico_lr_cache_update_selected_first_inv_final_read_validI
      `{!invGS Σ}
      E N N' sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
      sigma threads i cfg' Vread v Vread' :
    ↑N ⊆ E ->
    ↑N' ⊆ E ->
    cache_update_sequence_safe
      CT sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n ->
    nth_error
      threads
      i =
      Some
        (mkWMThread
          rΓ
          (cache_update_sequence_stmt tmp receiver cache_f n)
          Vthread) ->
    cache_update_sequence_selected_first_execution
      CT rΓ receiver tmp cache_f n Vthread sigma threads i cfg' ->
    (forall c1 c2,
      wm_step CT c1 c2 ->
      Forall
        (pico_lr_thread_entry (loc, cache_f) derived abs_vals)
        (wc_threads c1)) ->
    pico_cache_history_inv
      N
      (mkWMConfig sigma threads)
      (loc, cache_f)
      derived
      abs_vals -∗
    ⌜wm_read (wc_state cfg') Vread (loc, cache_f) v Vread'⌝ ={E}=∗
    ⌜derived_cache_msg_ok derived abs_vals v⌝.
  Proof.
    iIntros (Hsubset Hsubset' Hsafe Hnth Hselected Hallowed) "Hinv %Hread".
    assert (Hsteps : wm_steps CT (mkWMConfig sigma threads) cfg').
    {
      unfold cache_update_sequence_selected_first_execution in Hselected.
      eapply WMS_Step.
      - eapply WMS_Thread with
          (i := i)
          (t :=
            mkWMThread
              rΓ
              (cache_update_sequence_stmt tmp receiver cache_f n)
              Vthread)
          (t' :=
            mkWMThread
              (set_vars rΓ (update tmp (Int n) (vars rΓ)))
              (SFldWrite receiver cache_f tmp)
              Vthread).
        + exact Hnth.
        + eapply cache_update_sequence_safe_first_step_tail; eauto.
        + reflexivity.
      - exact Hselected.
    }
    iApply (pico_cache_history_inv_after_steps_read_valid
      E
      N
      N'
      CT
      (mkWMConfig sigma threads)
      cfg'
      Vread
      (loc, cache_f)
      v
      Vread'
      derived
      abs_vals
      with "Hinv"); eauto.
    intros c1 c2 Hstep.
    specialize (Hallowed c1 c2 Hstep).
    unfold pico_lr_thread_entry in Hallowed.
      apply (sem_typed_config_entries_cache_safe_config CT).
      exact Hallowed.
  Qed.

