      state_interp sigma ns (k ++ ks) nt ={E,∅}=∗
      ⌜exists sigma' V' rt a,
        wm_get_type sigma loc_x = Some rt /\
        sf_assignability_rel CT (rctype rt) f a /\
        runtime_vpa_assignability (rqtype rt) a = Assignable /\
        wm_write sigma sigma' V V' (loc_x, f) val_y⌝ ∗
      ▷ ∀ e' sigma',
        ⌜wm_thread_step
          CT
          sigma
          (mkWMThread rΓ (SFldWrite x f y) V)
          sigma'
          e'⌝ -∗
        ⌜wm_cache_history_state sigma addr derived abs_vals ->
          wm_cache_history_state sigma' addr derived abs_vals⌝ -∗
        £ 1 ={∅,E}=∗
        state_interp sigma' (S ns) ks nt ∗
        WP e' @ s; E {{ Φ }})
    -∗ WP (mkWMThread rΓ (SFldWrite x f y) V) @ s; E {{ Φ }}.
  Proof.
    iIntros (Hx Hy) "Hlr Hwp".
    iApply (pico_lr_thread_wp_step_exists with "Hlr").
    - apply pico_language_to_val_fld_write.
    - iIntros (sigma ns k ks nt) "Hstate".
      iMod ("Hwp" with "Hstate") as "[%Hwrite Hstep]".
      iModIntro.
      iSplit.
      + destruct s; simpl; auto.
        destruct Hwrite as
          [sigma' [V' [rt [a [Htype [Hfield [Hassign Hwrite]]]]]]].
        iPureIntro.
        eapply pico_fldwrite_thread_step_exists; eauto.
      + iExact "Hstep".
  Qed.

  Lemma wp_pico_lr_seqstep_step_progress
      s E Φ sΓ mt rΓ V s1 s2 addr derived abs_vals :
    pico_lr_threadI
      sΓ
      sΓ
      mt
      (mkWMThread rΓ (SSeq s1 s2) V)
      addr
      derived
      abs_vals -∗
    (∀ sigma ns k ks nt,
      state_interp sigma ns (k ++ ks) nt ={E,∅}=∗
      ⌜exists sigma' rΓ' s1' V',
        wm_thread_step
          CT
          sigma
          (mkWMThread rΓ s1 V)
          sigma'
          (mkWMThread rΓ' s1' V')⌝ ∗
      ▷ ∀ e' sigma',
        ⌜wm_thread_step
          CT
          sigma
          (mkWMThread rΓ (SSeq s1 s2) V)
          sigma'
          e'⌝ -∗
        ⌜wm_cache_history_state sigma addr derived abs_vals ->
          wm_cache_history_state sigma' addr derived abs_vals⌝ -∗
        £ 1 ={∅,E}=∗
        state_interp sigma' (S ns) ks nt ∗
        WP e' @ s; E {{ Φ }})
    -∗ WP (mkWMThread rΓ (SSeq s1 s2) V) @ s; E {{ Φ }}.
  Proof.
    iIntros "Hlr Hwp".
    iApply (pico_lr_thread_wp_step_exists with "Hlr").
    - apply pico_language_to_val_seq.
    - iIntros (sigma ns k ks nt) "Hstate".
      iMod ("Hwp" with "Hstate") as "[%Hsubstep Hstep]".
      iModIntro.
      iSplit.
      + destruct s; simpl; auto.
        destruct Hsubstep as [sigma' [rΓ' [s1' [V' Hsubstep]]]].
        iPureIntro.
        eapply pico_seqstep_thread_step_exists; eauto.
      + iExact "Hstep".
  Qed.

  Lemma wp_pico_lr_cache_update_tail_fldwrite_step_progress
      s E Φ sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n V :
    let tail_env := set_vars rΓ (update tmp (Int n) (vars rΓ)) in
    let tail := mkWMThread tail_env (SFldWrite receiver cache_f tmp) V in
    pico_lr_cache_update_sequenceI
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n -∗
    (∀ sigma ns k ks nt,
      state_interp sigma ns (k ++ ks) nt ={E,∅}=∗
      ⌜exists sigma' V' rt a,
        wm_get_type sigma loc = Some rt /\
        sf_assignability_rel CT (rctype rt) cache_f a /\
        runtime_vpa_assignability (rqtype rt) a = Assignable /\
        wm_write sigma sigma' V V' (loc, cache_f) (Int n)⌝ ∗
      ▷ ∀ e' sigma',
        ⌜wm_thread_step CT sigma tail sigma' e'⌝ -∗
        ⌜wm_cache_history_state sigma (loc, cache_f) derived abs_vals ->
          wm_cache_history_state sigma' (loc, cache_f) derived abs_vals⌝ -∗
        £ 1 ={∅,E}=∗
        state_interp sigma' (S ns) ks nt ∗
        WP e' @ s; E {{ Φ }})
    -∗ WP tail @ s; E {{ Φ }}.
  Proof.
    simpl.
    iIntros "Hseq Hwp".
    unfold pico_lr_threadI.
    unfold pico_lr_cache_update_sequenceI.
    iApply (wp_pico_sem_cache_update_tail_fldwrite_step_progress
      with "Hseq Hwp").
  Qed.

  Lemma wp_pico_lr_sem_cache_update_sequence_full_progress
      s E Φ sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n V :
    let tail :=
      mkWMThread
        (set_vars rΓ (update tmp (Int n) (vars rΓ)))
        (SFldWrite receiver cache_f tmp)
        V in
    let full :=
      mkWMThread
        rΓ
        (cache_update_sequence_stmt tmp receiver cache_f n)
        V in
    pico_lr_cache_update_sequenceI
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n -∗
    (∀ sigma ns k ks nt,
      state_interp sigma ns (k ++ ks) nt ={E,∅}=∗
      ▷ (£ 1 ={∅,E}=∗
        state_interp sigma (S ns) ks nt ∗
        (∀ sigma_tail ns_tail k_tail ks_tail nt_tail,
          state_interp
            sigma_tail
            ns_tail
            (k_tail ++ ks_tail)
            nt_tail ={E,∅}=∗
          ⌜exists sigma' V' rt a,
            wm_get_type sigma_tail loc = Some rt /\
            sf_assignability_rel CT (rctype rt) cache_f a /\
            runtime_vpa_assignability (rqtype rt) a = Assignable /\
            wm_write sigma_tail sigma' V V' (loc, cache_f) (Int n)⌝ ∗
          ▷ ∀ e' sigma',
            ⌜wm_thread_step CT sigma_tail tail sigma' e'⌝ -∗
            ⌜wm_cache_history_state
                sigma_tail
                (loc, cache_f)
                derived
                abs_vals ->
              wm_cache_history_state
                sigma'
                (loc, cache_f)
                derived
                abs_vals⌝ -∗
            £ 1 ={∅,E}=∗
            state_interp sigma' (S ns_tail) ks_tail nt_tail ∗
            WP e' @ s; E {{ Φ }})))
    -∗ WP full @ s; E {{ Φ }}.
  Proof.
    simpl.
    iIntros "Hseq Hprogress".
    unfold pico_lr_cache_update_sequenceI.
    iApply (wp_pico_lift_sem_cache_update_sequence_full_progress
      with "Hseq Hprogress").
  Qed.

  Lemma wp_pico_lr_cache_compute_then_write_tail_step
      s E Φ sΓ sΓ_mid mt rΓ rΓ_mid loc cache_f receiver tmp compute
