  Lemma pico_lr_config_seqstep_residual_step_update :
    forall sigma sigma' threads i rΓ rΓ' V V' s1 s1' s2
      sΓ sΓ_mid sΓ'' mt addr derived abs_vals,
      nth_error threads i = Some (mkWMThread rΓ (SSeq s1 s2) V) ->
      wm_thread_step CT
        sigma
        (mkWMThread rΓ s1 V)
        sigma'
        (mkWMThread rΓ' s1' V') ->
      stmt_typing CT sΓ mt s1' sΓ_mid ->
      stmt_typing CT sΓ_mid mt s2 sΓ'' ->
      cache_safe_thread
        (mkWMThread rΓ' s1' V') addr derived abs_vals ->
      cache_safe_thread
        (mkWMThread rΓ' s2 V') addr derived abs_vals ->
      pico_lr_config_interp
        addr derived abs_vals
        (mkWMConfig sigma threads) ->
      pico_lr_config_interp
        addr derived abs_vals
        (mkWMConfig
          sigma'
          (update
            i
            (mkWMThread rΓ' (residual_seq_wm s1' s2) V')
            threads)).
  Proof.
    intros sigma sigma' threads i rΓ rΓ' V V' s1 s1' s2
           sΓ sΓ_mid sΓ'' mt addr derived abs_vals
           Hnth Hstep Htype1 Htype2 Hsafe1 Hsafe2 Hinterp.
    eapply pico_lr_config_seqstep_step_update; eauto.
    eapply pico_lr_thread_entry_seqstep_residual_post; eauto.
  Qed.

  Lemma pico_lr_config_seqstep_assign_int_step_update :
    forall sigma threads i rΓ V x n old_v s2 addr derived abs_vals,
      nth_error threads i =
        Some (mkWMThread rΓ (SSeq (SVarAss x (EInt n)) s2) V) ->
      runtime_getVal rΓ x = Some old_v ->
      cache_safe_thread
        (mkWMThread
          (set_vars rΓ (update x (Int n) (vars rΓ)))
          s2
          V)
        addr
        derived
        abs_vals ->
      pico_lr_config_interp
        addr derived abs_vals
        (mkWMConfig sigma threads) ->
      pico_lr_config_interp
        addr derived abs_vals
        (mkWMConfig
          sigma
          (update
            i
            (mkWMThread
              (set_vars rΓ (update x (Int n) (vars rΓ)))
              s2
              V)
            threads)).
  Proof.
    intros sigma threads i rΓ V x n old_v s2 addr derived abs_vals
           Hnth Hruntime Hsafe2 Hinterp.
    unfold pico_lr_config_interp in *.
    apply Forall_update.
    - exact Hinterp.
    - eapply sem_typed_thread_entry_seqstep_assign_int_post; eauto.
      eapply Forall_nth_error; eauto.
    - apply nth_error_Some.
      rewrite Hnth.
      discriminate.
  Qed.

  Lemma pico_lr_config_seqstep_field_read_step_update :
    forall sigma threads i rΓ V V' x y f loc_y v s2
      addr derived abs_vals,
      nth_error threads i =
        Some (mkWMThread rΓ (SSeq (SVarAss x (EField y f)) s2) V) ->
      runtime_getVal rΓ y = Some (Iot loc_y) ->
      wm_read sigma V (loc_y, f) v V' ->
