            i
            (mkWMThread
              (set_vars rΓ (update x v (vars rΓ)))
              s2
              V')
            threads)).
  Proof.
    intros sigma threads i rΓ V V' x y f loc_y v s2
           addr derived abs_vals Hnth Hruntime Hread Hsafe2 Hinterp.
    unfold pico_lr_config_interp in *.
    apply Forall_update.
    - exact Hinterp.
    - eapply sem_typed_thread_entry_seqstep_field_read_post; eauto.
      eapply Forall_nth_error; eauto.
    - apply nth_error_Some.
      rewrite Hnth.
      discriminate.
