  Lemma pico_lr_config_seqstep_fldwrite_step_update :
    forall sigma sigma' threads i rΓ V V' x f y loc_x rt a val_y s2
      addr derived abs_vals,
      nth_error threads i =
        Some (mkWMThread rΓ (SSeq (SFldWrite x f y) s2) V) ->
      runtime_getVal rΓ x = Some (Iot loc_x) ->
      wm_get_type sigma loc_x = Some rt ->
      sf_assignability_rel CT (rctype rt) f a ->
      runtime_getVal rΓ y = Some val_y ->
      runtime_vpa_assignability (rqtype rt) a = Assignable ->
      wm_write sigma sigma' V V' (loc_x, f) val_y ->
      cache_safe_thread
        (mkWMThread rΓ s2 V')
        addr
        derived
        abs_vals ->
      pico_lr_config_interp
        addr derived abs_vals
        (mkWMConfig sigma threads) ->
      pico_lr_config_interp
        addr derived abs_vals
        (mkWMConfig
          sigma'
          (update i (mkWMThread rΓ s2 V') threads)).
  Proof.
    intros sigma sigma' threads i rΓ V V' x f y loc_x rt a val_y s2
           addr derived abs_vals Hnth _ _ _ _ _ _ Hsafe2 Hinterp.
    unfold pico_lr_config_interp in *.
    apply Forall_update.
    - exact Hinterp.
    - eapply sem_typed_thread_entry_seqstep_fldwrite_post; eauto.
      eapply Forall_nth_error; eauto.
    - apply nth_error_Some.
      rewrite Hnth.
      discriminate.
  Qed.

  Inductive pico_lr_covered_thread_step_post
      (addr : FieldAddr) (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) :
      wm_state -> wm_thread -> wm_state -> wm_thread -> Prop :=
  | PLR_Covered_AssignInt :
      forall sigma rΓ V x n old_v,
        runtime_getVal rΓ x = Some old_v ->
        pico_lr_covered_thread_step_post
          addr
          derived
          abs_vals
          sigma
          (mkWMThread rΓ (SVarAss x (EInt n)) V)
          sigma
          (mkWMThread
            (set_vars rΓ (update x (Int n) (vars rΓ)))
            SSkip
            V)
  | PLR_Covered_FieldRead :
      forall sigma rΓ V V' x y f loc_y v,
        runtime_getVal rΓ y = Some (Iot loc_y) ->
        wm_read sigma V (loc_y, f) v V' ->
        pico_lr_covered_thread_step_post
          addr
          derived
          abs_vals
          sigma
          (mkWMThread rΓ (SVarAss x (EField y f)) V)
          sigma
          (mkWMThread
            (set_vars rΓ (update x v (vars rΓ)))
            SSkip
            V')
  | PLR_Covered_FldWrite :
      forall sigma sigma' rΓ V V' x f y loc_x rt a val_y,
        runtime_getVal rΓ x = Some (Iot loc_x) ->
        wm_get_type sigma loc_x = Some rt ->
        sf_assignability_rel CT (rctype rt) f a ->
        runtime_getVal rΓ y = Some val_y ->
        runtime_vpa_assignability (rqtype rt) a = Assignable ->
        wm_write sigma sigma' V V' (loc_x, f) val_y ->
        pico_lr_covered_thread_step_post
          addr
          derived
          abs_vals
          sigma
          (mkWMThread rΓ (SFldWrite x f y) V)
          sigma'
          (mkWMThread rΓ SSkip V')
  | PLR_Covered_SeqSkip :
      forall sigma rΓ V s2,
        pico_lr_covered_thread_step_post
          addr
          derived
          abs_vals
          sigma
          (mkWMThread rΓ (SSeq SSkip s2) V)
          sigma
          (mkWMThread rΓ s2 V)
  | PLR_Covered_SeqStepResidual :
      forall sigma sigma' rΓ rΓ' V V' s1 s1' s2,
        wm_thread_step CT
          sigma
          (mkWMThread rΓ s1 V)
          sigma'
          (mkWMThread rΓ' s1' V') ->
        pico_lr_thread_entry
          addr
          derived
          abs_vals
          (mkWMThread rΓ' (residual_seq_wm s1' s2) V') ->
        pico_lr_covered_thread_step_post
          addr
          derived
          abs_vals
          sigma
          (mkWMThread rΓ (SSeq s1 s2) V)
          sigma'
          (mkWMThread rΓ' (residual_seq_wm s1' s2) V')
  | PLR_Covered_SeqStepAssignInt :
      forall sigma rΓ V x n old_v s2,
        runtime_getVal rΓ x = Some old_v ->
        cache_safe_thread
          (mkWMThread
            (set_vars rΓ (update x (Int n) (vars rΓ)))
            s2
            V)
          addr
          derived
          abs_vals ->
        pico_lr_covered_thread_step_post
          addr
          derived
          abs_vals
          sigma
          (mkWMThread rΓ (SSeq (SVarAss x (EInt n)) s2) V)
          sigma
          (mkWMThread
            (set_vars rΓ (update x (Int n) (vars rΓ)))
            s2
            V)
  | PLR_Covered_SeqStepFieldRead :
      forall sigma rΓ V V' x y f loc_y v s2,
        runtime_getVal rΓ y = Some (Iot loc_y) ->
        wm_read sigma V (loc_y, f) v V' ->
        cache_safe_thread
          (mkWMThread
            (set_vars rΓ (update x v (vars rΓ)))
            s2
            V')
          addr
          derived
          abs_vals ->
        pico_lr_covered_thread_step_post
          addr
          derived
          abs_vals
          sigma
          (mkWMThread rΓ (SSeq (SVarAss x (EField y f)) s2) V)
          sigma
          (mkWMThread
            (set_vars rΓ (update x v (vars rΓ)))
            s2
            V')
  | PLR_Covered_SeqStepFldWrite :
      forall sigma sigma' rΓ V V' x f y loc_x rt a val_y s2,
        runtime_getVal rΓ x = Some (Iot loc_x) ->
        wm_get_type sigma loc_x = Some rt ->
        sf_assignability_rel CT (rctype rt) f a ->
        runtime_getVal rΓ y = Some val_y ->
        runtime_vpa_assignability (rqtype rt) a = Assignable ->
        wm_write sigma sigma' V V' (loc_x, f) val_y ->
        cache_safe_thread
          (mkWMThread rΓ s2 V')
          addr
          derived
          abs_vals ->
        pico_lr_covered_thread_step_post
          addr
          derived
          abs_vals
          sigma
          (mkWMThread rΓ (SSeq (SFldWrite x f y) s2) V)
          sigma'
          (mkWMThread rΓ s2 V').

  Definition pico_lr_covered_stepsI
      (addr : FieldAddr) (derived : list Syntax.value -> nat)
      (abs_vals : list Syntax.value) : iProp Σ :=
    ⌜forall c1 c2,
      wm_step CT c1 c2 ->
      forall sigma sigma' threads i t t',
        c1 = mkWMConfig sigma threads ->
        nth_error threads i = Some t ->
        wm_thread_step CT sigma t sigma' t' ->
        pico_lr_covered_thread_step_post
          addr derived abs_vals sigma t sigma' t'⌝%I.

  Lemma pico_lr_covered_stepsI_intro :
    forall addr derived abs_vals,
      (forall c1 c2,
        wm_step CT c1 c2 ->
        forall sigma sigma' threads i t t',
          c1 = mkWMConfig sigma threads ->
          nth_error threads i = Some t ->
          wm_thread_step CT sigma t sigma' t' ->
          pico_lr_covered_thread_step_post
            addr derived abs_vals sigma t sigma' t') ->
      ⊢ pico_lr_covered_stepsI addr derived abs_vals.
  Proof.
    intros addr derived abs_vals Hcovered.
    iPureIntro.
    exact Hcovered.
  Qed.

  Lemma pico_lr_covered_stepsI_elim :
    forall addr derived abs_vals,
      pico_lr_covered_stepsI addr derived abs_vals -∗
      ⌜forall c1 c2,
        wm_step CT c1 c2 ->
        forall sigma sigma' threads i t t',
          c1 = mkWMConfig sigma threads ->
          nth_error threads i = Some t ->
          wm_thread_step CT sigma t sigma' t' ->
          pico_lr_covered_thread_step_post
            addr derived abs_vals sigma t sigma' t'⌝.
  Proof.
    iIntros (addr derived abs_vals) "Hcovered".
    iExact "Hcovered".
  Qed.

  Lemma pico_lr_covered_thread_step_post_entry :
    forall addr derived abs_vals sigma t sigma' t',
      pico_lr_covered_thread_step_post
        addr derived abs_vals sigma t sigma' t' ->
      pico_lr_thread_entry addr derived abs_vals t ->
      pico_lr_thread_entry addr derived abs_vals t'.
  Proof.
    intros addr derived abs_vals sigma t sigma' t' Hcovered Hentry.
    inversion Hcovered; subst; eauto using
      pico_lr_thread_entry_assign_int_post,
      pico_lr_thread_entry_field_read_post,
      pico_lr_thread_entry_fldwrite_post,
      pico_lr_thread_entry_seqskip_post,
      pico_lr_thread_entry_seqstep_assign_int_post,
      pico_lr_thread_entry_seqstep_field_read_post,
      pico_lr_thread_entry_seqstep_fldwrite_post.
  Qed.

  Lemma pico_lr_config_covered_step_update :
    forall cfg cfg' addr derived abs_vals,
      wm_step CT cfg cfg' ->
      pico_lr_config_interp addr derived abs_vals cfg ->
      (forall sigma sigma' threads i t t',
        cfg = mkWMConfig sigma threads ->
        nth_error threads i = Some t ->
        wm_thread_step CT sigma t sigma' t' ->
        pico_lr_covered_thread_step_post
          addr derived abs_vals sigma t sigma' t') ->
      pico_lr_config_interp addr derived abs_vals cfg'.
  Proof.
    intros cfg cfg' addr derived abs_vals Hstep Hinterp Hcovered.
    inversion Hstep as
      [sigma sigma' threads threads' i t t' Hnth Hthread Hthreads'];
      subst.
    unfold pico_lr_config_interp in *.
    simpl in *.
    apply Forall_update.
    - exact Hinterp.
    - assert (Hentry : pico_lr_thread_entry addr derived abs_vals t).
      {
        unfold pico_lr_thread_entry.
        eapply Forall_nth_error; eauto.
      }
      pose proof
        (pico_lr_covered_thread_step_post_entry
          addr derived abs_vals sigma t sigma' t'
          (Hcovered sigma sigma' threads i t t' eq_refl Hnth Hthread)
          Hentry) as Hentry'.
      unfold pico_lr_thread_entry in Hentry'.
      exact Hentry'.
    - apply nth_error_Some.
      rewrite Hnth.
      discriminate.
  Qed.

  Lemma pico_lr_config_step_closure_from_covered :
    forall addr derived abs_vals,
      (forall c1 c2,
        wm_step CT c1 c2 ->
        forall sigma sigma' threads i t t',
          c1 = mkWMConfig sigma threads ->
          nth_error threads i = Some t ->
          wm_thread_step CT sigma t sigma' t' ->
          pico_lr_covered_thread_step_post
            addr derived abs_vals sigma t sigma' t') ->
      pico_lr_config_step_closure addr derived abs_vals.
  Proof.
    intros addr derived abs_vals Hcovered c1 c2 Hstep Hinterp.
    eapply pico_lr_config_covered_step_update; eauto.
  Qed.

  Lemma pico_lr_config_step_closureI_from_covered :
    forall addr derived abs_vals,
      (forall c1 c2,
        wm_step CT c1 c2 ->
        forall sigma sigma' threads i t t',
          c1 = mkWMConfig sigma threads ->
          nth_error threads i = Some t ->
          wm_thread_step CT sigma t sigma' t' ->
          pico_lr_covered_thread_step_post
            addr derived abs_vals sigma t sigma' t') ->
      ⊢ pico_lr_config_step_closureI addr derived abs_vals.
  Proof.
    intros addr derived abs_vals Hcovered.
    iApply pico_lr_config_step_closureI_intro.
    eapply pico_lr_config_step_closure_from_covered; eauto.
  Qed.

  Lemma pico_lr_config_step_closureI_from_coveredI :
    forall addr derived abs_vals,
      pico_lr_covered_stepsI addr derived abs_vals -∗
      pico_lr_config_step_closureI addr derived abs_vals.
  Proof.
    iIntros (addr derived abs_vals) "HcoveredI".
    iDestruct (pico_lr_covered_stepsI_elim with "HcoveredI") as %Hcovered.
    iApply pico_lr_config_step_closureI_intro.
    eapply pico_lr_config_step_closure_from_covered; eauto.
  Qed.

  Lemma pico_lr_config_execution_prefix_read_specI_from_thread_postI :
    forall cfg cfg' V addr v V' derived abs_vals,
      wm_steps CT cfg cfg' ->
      wm_config_cache_history_state cfg addr derived abs_vals ->
      wm_read (wc_state cfg') V addr v V' ->
      pico_lr_configI cfg addr derived abs_vals -∗
      pico_lr_thread_post_stepsI addr derived abs_vals -∗
      pico_lr_config_execution_prefix_read_specI
        cfg cfg' V addr v V' derived abs_vals.
  Proof.
    iIntros (cfg cfg' V addr v V' derived abs_vals
             Hsteps Hstate Hread) "Hcfg Hpost".
    iPoseProof (pico_lr_config_step_closureI_from_thread_postI with "Hpost")
      as "Hclosed".
    iApply (pico_lr_config_execution_prefix_read_specI_from_closureI
      cfg cfg' V addr v V' derived abs_vals Hsteps Hstate Hread
      with "Hcfg Hclosed").
  Qed.

  Lemma pico_lr_config_execution_prefix_read_specI_from_coveredI :
    forall cfg cfg' V addr v V' derived abs_vals,
      wm_steps CT cfg cfg' ->
      wm_config_cache_history_state cfg addr derived abs_vals ->
      wm_read (wc_state cfg') V addr v V' ->
      pico_lr_configI cfg addr derived abs_vals -∗
      pico_lr_covered_stepsI addr derived abs_vals -∗
      pico_lr_config_execution_prefix_read_specI
        cfg cfg' V addr v V' derived abs_vals.
  Proof.
    iIntros (cfg cfg' V addr v V' derived abs_vals
             Hsteps Hstate Hread) "Hcfg Hcovered".
    iPoseProof (pico_lr_config_step_closureI_from_coveredI with "Hcovered")
      as "Hclosed".
    iApply (pico_lr_config_execution_prefix_read_specI_from_closureI
      cfg cfg' V addr v V' derived abs_vals Hsteps Hstate Hread
      with "Hcfg Hclosed").
  Qed.

  Lemma pico_lr_cache_update_execution_evidenceI_from_coveredI :
    forall rΓ receiver tmp cache_f n V sigma threads i cfg'
           addr derived abs_vals,
      pico_lr_cache_update_selected_first_executionI
        rΓ receiver tmp cache_f n V sigma threads i cfg' -∗
      pico_lr_covered_stepsI addr derived abs_vals -∗
      pico_lr_cache_update_execution_evidenceI
        rΓ receiver tmp cache_f n V sigma threads i cfg'
        addr derived abs_vals.
  Proof.
    iIntros (rΓ receiver tmp cache_f n V sigma threads i cfg'
             addr derived abs_vals) "Hexec Hcovered".
    iPoseProof (pico_lr_config_step_closureI_from_coveredI with "Hcovered")
      as "Hclosed".
    iApply (pico_lr_cache_update_execution_evidenceI_intro
      with "Hexec Hclosed").
  Qed.

  Lemma pico_lr_cache_update_execution_specI_from_coveredI :
    forall sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n V
           sigma threads i cfg',
      pico_lr_cache_update_sequenceI
        sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n -∗
      pico_lr_configI
        (mkWMConfig sigma threads)
        (loc, cache_f)
        derived
        abs_vals -∗
      wm_config_cache_history_stateI
        (mkWMConfig sigma threads)
        (loc, cache_f)
        derived
        abs_vals -∗
      ⌜nth_error
        threads
        i =
        Some
          (mkWMThread
            rΓ
            (cache_update_sequence_stmt tmp receiver cache_f n)
            V)⌝ -∗
      pico_lr_cache_update_selected_first_executionI
        rΓ receiver tmp cache_f n V sigma threads i cfg' -∗
      pico_lr_covered_stepsI (loc, cache_f) derived abs_vals -∗
      pico_lr_cache_update_execution_specI
        sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n V
        sigma threads i cfg'.
  Proof.
    iIntros (sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n V
             sigma threads i cfg')
      "Hseq Hcfg Hhist Hnth Hexec Hcovered".
    iPoseProof (pico_lr_config_step_closureI_from_coveredI with "Hcovered")
      as "Hclosed".
    iApply (pico_lr_cache_update_execution_specI_from_closureI
      with "Hseq Hcfg Hhist Hnth Hexec Hclosed").
  Qed.

  Lemma pico_lr_cache_update_execution_specI_from_safe_coveredI :
    forall sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n V
           sigma threads i cfg',
      cache_update_sequence_safe
        CT sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n ->
      nth_error
        threads
        i =
        Some
          (mkWMThread
            rΓ
            (cache_update_sequence_stmt tmp receiver cache_f n)
            V) ->
      cache_update_sequence_selected_first_execution
        CT rΓ receiver tmp cache_f n V sigma threads i cfg' ->
      wm_config_cache_history_state
        (mkWMConfig sigma threads)
        (loc, cache_f)
        derived
        abs_vals ->
      pico_lr_configI
        (mkWMConfig sigma threads)
        (loc, cache_f)
        derived
        abs_vals -∗
      pico_lr_covered_stepsI (loc, cache_f) derived abs_vals -∗
      pico_lr_cache_update_execution_specI
        sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n V
        sigma threads i cfg'.
  Proof.
    iIntros (sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n V
             sigma threads i cfg' Hsafe Hnth Hselected Hstate)
      "Hcfg Hcovered".
    iPoseProof (pico_lr_config_step_closureI_from_coveredI with "Hcovered")
      as "Hclosed".
    iApply (pico_lr_cache_update_execution_specI_from_safe_closureI
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n V
      sigma threads i cfg' Hsafe Hnth Hselected Hstate
      with "Hcfg Hclosed").
  Qed.

  Lemma pico_lr_config_closed_steps_read_validI :
    forall cfg cfg' V addr v V' derived abs_vals,
      wm_steps CT cfg cfg' ->
      pico_lr_config_interp addr derived abs_vals cfg ->
      (forall c1 c2,
        wm_step CT c1 c2 ->
        pico_lr_config_interp addr derived abs_vals c1 ->
        pico_lr_config_interp addr derived abs_vals c2) ->
      wm_config_cache_history_state cfg addr derived abs_vals ->
      wm_read (wc_state cfg') V addr v V' ->
      ⊢ (⌜derived_cache_msg_ok derived abs_vals v⌝ : iProp Σ).
  Proof.
    intros cfg cfg' V addr v V' derived abs_vals
           Hsteps Hinterp Hclosed Hstate Hread.
    unfold pico_lr_config_interp in *.
    iApply sem_typed_config_entry_interpretation_closed_final_read_validI;
      eauto.
  Qed.

  Lemma pico_lr_config_closed_steps_read_valid_genericI :
    forall cfg cfg' V addr v V' derived abs_vals,
      wm_steps CT cfg cfg' ->
      pico_lr_config_interp addr derived abs_vals cfg ->
      (forall c1 c2,
        wm_step CT c1 c2 ->
        pico_lr_config_interp addr derived abs_vals c1 ->
        pico_lr_config_interp addr derived abs_vals c2) ->
      wm_config_cache_history_state cfg addr derived abs_vals ->
      wm_read (wc_state cfg') V addr v V' ->
      ⊢ (⌜cache_valid
            (derived_cache_protocol derived)
            abs_vals
            DerivedCacheField
            v⌝ : iProp Σ).
  Proof.
    intros cfg cfg' V addr v V' derived abs_vals
           Hsteps Hinterp Hclosed Hstate Hread.
    unfold pico_lr_config_interp in *.
    iApply sem_typed_config_entry_interpretation_closed_final_read_valid_genericI;
      eauto.
  Qed.

  Lemma pico_lr_config_closed_steps_preserve_cache_history :
    forall cfg cfg' addr derived abs_vals,
      wm_steps CT cfg cfg' ->
      pico_lr_config_interp addr derived abs_vals cfg ->
      (forall c1 c2,
        wm_step CT c1 c2 ->
        pico_lr_config_interp addr derived abs_vals c1 ->
        pico_lr_config_interp addr derived abs_vals c2) ->
      wm_config_cache_history_state cfg addr derived abs_vals ->
      wm_config_cache_history_state cfg' addr derived abs_vals.
  Proof.
    intros cfg cfg' addr derived abs_vals
           Hsteps Hinterp Hclosed Hstate.
    revert Hinterp Hstate.
    induction Hsteps as [cfg0 | cfg1 cfg2 cfg3 Hstep Htail IH];
      intros Hinterp Hstate.
    - exact Hstate.
    - apply IH.
      + eapply Hclosed; eauto.
      + eapply wm_step_preserves_cache_history; eauto.
        eapply wm_step_cache_safe_from_config_allowed; eauto.
        apply cache_safe_config_implies_wm_config_threads_allowed.
        unfold pico_lr_config_interp in Hinterp.
        apply (sem_typed_config_entry_interpretation_cache_safe_config CT).
        exact Hinterp.
  Qed.

  Lemma pico_lr_config_closure_steps_read_validI :
