    intros cfg cfg' addr derived abs_vals
           Hsteps Hinterp Hcovered Hstate.
    revert Hinterp Hstate.
    induction Hsteps as [cfg0 | cfg1 cfg2 cfg3 Hstep Htail IH];
      intros Hinterp Hstate.
