  Lemma pico_lr_cache_compute_then_write_phases_tail_inv_closure_read_valid
      `{!invGS Σ}
      E N sΓ sΓ_mid mt rΓ rΓ_mid loc cache_f receiver tmp compute
      derived abs_vals V sigma cfg' Vread v Vread' :
    ↑N ⊆ E ->
    let tail_cfg :=
      mkWMConfig
        sigma
        [mkWMThread rΓ_mid (SFldWrite receiver cache_f tmp) V] in
    wm_steps CT tail_cfg cfg' ->
    wm_read (wc_state cfg') Vread (loc, cache_f) v Vread' ->
    pico_lr_cache_compute_then_write_phasesI
      sΓ sΓ_mid mt rΓ rΓ_mid loc cache_f receiver tmp compute
      derived abs_vals -∗
    pico_lr_config_step_closureI (loc, cache_f) derived abs_vals -∗
    pico_cache_history_inv N tail_cfg (loc, cache_f) derived abs_vals ={E}=∗
    ⌜derived_cache_msg_ok derived abs_vals v⌝.
  Proof.
    iIntros (Hsubset tail_cfg Hsteps Hread) "Hphases Hclosed Hinv".
    iPoseProof
      (pico_lr_cache_compute_then_write_phases_tail_configI
        with "Hphases") as "Hcfg".
    iDestruct "Hclosed" as "%Hclosed".
    iDestruct (pico_lr_configI_interp with "Hcfg") as "%Hinterp".
    iInv N as ">Hstate" "Hclose".
    iDestruct "Hstate" as "%Hstate".
    iMod ("Hclose" with "[]") as "_".
    {
      iNext.
      iPureIntro.
      exact Hstate.
    }
    iModIntro.
    iPureIntro.
    pose proof
      (pico_lr_config_closed_steps_preserve_cache_history
        tail_cfg cfg' (loc, cache_f) derived abs_vals
        Hsteps Hinterp Hclosed Hstate) as Hfinal.
    eapply wm_config_cache_history_state_read_valid; eauto.
  Qed.

