  Lemma pico_lr_fldwrite_state_step_update
      `{!invGS Σ} `{!PicoIrisGhostState.picoCacheG Σ}
      E N N' sΓ sΓ' mt sigma sigma' rΓ V V'
      x f y loc_x val_y addr derived abs_vals :
    ↑N ⊆ E ->
    runtime_getVal rΓ x = Some (Iot loc_x) ->
    runtime_getVal rΓ y = Some val_y ->
    wm_write sigma sigma' V V' (loc_x, f) val_y ->
    pico_lr_stmtI
      sΓ
      sΓ'
