    pico_lr_stmtI
      sΓ
      sΓ'
      mt
      rΓ
      (SFldWrite x f y)
      addr
      derived
      abs_vals -∗
    pico_lr_envI sigma qcontext sΓ rΓ -∗
    pico_cache_state_interp
      N
      (mkWMConfig sigma [mkWMThread rΓ (SFldWrite x f y) V])
      addr
      derived
      abs_vals ={E}=∗
    pico_lr_envI
      sigma'
      qcontext
      sΓ
      (wt_env (mkWMThread rΓ SSkip V')) ∗
    pico_cache_state_interp
      N'
      (mkWMConfig sigma' [mkWMThread rΓ SSkip V'])
      addr
      derived
      abs_vals.
