    iIntros (Hsubset Hx Hy Hwrite) "Hstmt Henv Hstate".
    iMod (pico_lr_fldwrite_state_step_update
      E N N' sΓ sΓ' mt sigma sigma' rΓ V V'
      x f y loc_x val_y addr derived abs_vals with
      "Hstmt Hstate") as "Hstate'"; eauto.
    iModIntro.
