  Lemma pico_lr_config_state_steps_read_valid
      `{!invGS Σ} `{!PicoIrisGhostState.picoCacheG Σ}
      E N N' cfg cfg' V addr v V' derived abs_vals :
    ↑N ⊆ E ->
    ↑N' ⊆ E ->
    wm_steps CT cfg cfg' ->
    (forall c1 c2,
      wm_step CT c1 c2 ->
      pico_lr_config_interp addr derived abs_vals c1) ->
