  Lemma pico_lr_cache_update_execution_specI_inv_after_execution
      `{!invGS Σ}
      E N N' sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
      sigma threads i cfg' :
    ↑N ⊆ E ->
    pico_lr_cache_update_execution_specI
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
      sigma threads i cfg' -∗
    pico_cache_history_inv
      N
      (mkWMConfig sigma threads)
      (loc, cache_f)
      derived
      abs_vals ={E}=∗
    pico_lr_cache_update_execution_specI
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
      sigma threads i cfg' ∗
    pico_cache_history_inv
      N'
      cfg'
      (loc, cache_f)
      derived
      abs_vals.
  Proof.
    iIntros (Hsubset) "Hspec Hinv".
    iDestruct "Hspec" as "(Hseq & Hcfg & Hhist & %Hnth & Hevidence)".
    iDestruct "Hseq" as %Hsafe.
    iDestruct "Hhist" as %Hhist.
    iDestruct "Hevidence" as "[Hexec Hclosed]".
    iDestruct "Hexec" as %Hselected.
    iDestruct "Hclosed" as %Hclosed.
    iDestruct (pico_lr_configI_interp with "Hcfg") as %Hinterp.
    pose proof (pico_lr_cache_update_selected_first_steps
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
      sigma threads i cfg' Hsafe Hnth Hselected) as Hsteps.
    iPoseProof (pico_lr_cache_update_sequence_intro
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Hsafe)
      as "Hseq".
    iPoseProof (wm_config_cache_history_stateI_intro
      (mkWMConfig sigma threads) (loc, cache_f) derived abs_vals Hhist)
      as "Hhist".
    iPoseProof (pico_lr_cache_update_selected_first_executionI_intro
      rΓ receiver tmp cache_f n Vthread sigma threads i cfg' Hselected)
      as "Hexec".
    iPoseProof (pico_lr_config_step_closureI_intro
      (loc, cache_f) derived abs_vals Hclosed) as "Hclosed".
    iPoseProof (pico_lr_config_execution_prefixI_from_closureI
      (mkWMConfig sigma threads) cfg' (loc, cache_f) derived abs_vals
      Hsteps with "Hcfg Hclosed") as "Hprefix".
    iMod (pico_lr_config_inv_execution_prefix_steps_update
      E N N' (mkWMConfig sigma threads) cfg'
      (loc, cache_f) derived abs_vals Hsubset Hsteps
      with "Hprefix Hinv") as "Hinv'".
    iPoseProof (pico_lr_configI_from_entries
      (mkWMConfig sigma threads) (loc, cache_f) derived abs_vals
      (pico_lr_config_interp_entries
        (mkWMConfig sigma threads) (loc, cache_f) derived abs_vals
        Hinterp)) as "Hcfg".
    iPoseProof (pico_lr_cache_update_execution_evidenceI_intro
      with "Hexec Hclosed") as "Hevidence".
    iModIntro.
    iSplitL "Hseq Hcfg Hhist Hevidence".
    - iApply (pico_lr_cache_update_execution_specI_intro
        with "Hseq Hcfg Hhist [] Hevidence").
      iPureIntro.
      exact Hnth.
    - iExact "Hinv'".
  Qed.

  Lemma pico_lr_cache_update_execution_specI_inv_alloc_after_execution
      `{!invGS Σ}
      (N N' : namespace)
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
      sigma threads i cfg' :
    pico_lr_cache_update_execution_specI
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
      sigma threads i cfg' -∗
    |={⊤}=>
    pico_lr_cache_update_execution_specI
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
      sigma threads i cfg' ∗
    pico_cache_history_inv
      N'
      cfg'
      (loc, cache_f)
      derived
      abs_vals.
  Proof.
    iIntros "Hspec".
    iDestruct "Hspec" as "(Hseq & Hcfg & Hhist & %Hnth & Hevidence)".
    iDestruct "Hhist" as %Hstate.
    iMod (pico_cache_history_inv_alloc
      N
      (mkWMConfig sigma threads)
      (loc, cache_f)
      derived
      abs_vals
      Hstate) as "Hinv".
    iPoseProof (wm_config_cache_history_stateI_intro
      (mkWMConfig sigma threads) (loc, cache_f) derived abs_vals Hstate)
      as "Hhist".
    iPoseProof (pico_lr_cache_update_execution_specI_intro
      with "Hseq Hcfg Hhist [] Hevidence") as "Hspec".
    {
      iPureIntro.
      exact Hnth.
    }
    iApply (pico_lr_cache_update_execution_specI_inv_after_execution
      ⊤ N N' sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
      sigma threads i cfg' with "Hspec Hinv").
    set_solver.
  Qed.

