  Lemma pico_lr_cache_update_execution_specI_state_after_execution
      `{!invGS Σ} `{!PicoIrisGhostState.picoCacheG Σ}
      E N N' sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
      sigma threads i cfg' :
    ↑N ⊆ E ->
    pico_lr_cache_update_execution_specI
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
      sigma threads i cfg' -∗
    pico_cache_state_interp
      N
      (mkWMConfig sigma threads)
      (loc, cache_f)
      derived
      abs_vals ={E}=∗
    pico_lr_cache_update_execution_specI
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
      sigma threads i cfg' ∗
    pico_cache_state_interp
      N'
      cfg'
      (loc, cache_f)
      derived
      abs_vals.
  Proof.
    iIntros (Hsubset) "Hspec Hstate".
    iDestruct "Hspec" as "(Hseq & Hcfg & Hhist & %Hnth & Hevidence)".
    iDestruct "Hseq" as %Hsafe.
    iDestruct "Hhist" as %Hhist.
    iDestruct "Hevidence" as "[Hexec Hclosed]".
    iDestruct "Hexec" as %Hselected.
    iDestruct "Hclosed" as %Hclosed.
    pose proof (pico_lr_cache_update_selected_first_steps
      sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
      sigma threads i cfg' Hsafe Hnth Hselected) as Hsteps.
    iDestruct (pico_lr_configI_interp with "Hcfg") as %Hinterp.
    iMod (pico_cache_state_interp_after_steps_preserved
      E
      N
      N'
      (mkWMConfig sigma threads)
      cfg'
      (loc, cache_f)
      derived
      abs_vals
      with "Hstate") as "Hstate'".
    - exact Hsubset.
    - intros Hstate0.
      eapply pico_lr_config_closed_steps_preserve_cache_history; eauto.
    - iPoseProof (pico_lr_cache_update_sequence_intro
        sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Hsafe)
        as "Hseq".
      iPoseProof (wm_config_cache_history_stateI_intro
        (mkWMConfig sigma threads) (loc, cache_f) derived abs_vals Hhist)
        as "Hhist".
      iPoseProof (pico_lr_cache_update_selected_first_executionI_intro
        rΓ receiver tmp cache_f n Vthread sigma threads i cfg' Hselected)
        as "Hexec".
      iPoseProof (pico_lr_config_step_closureI_intro
        (loc, cache_f) derived abs_vals Hclosed) as "Hclosed".
      iPoseProof (pico_lr_cache_update_execution_evidenceI_intro
        with "Hexec Hclosed") as "Hevidence".
      iModIntro.
      iSplitL "Hseq Hcfg Hhist Hevidence".
      + iApply (pico_lr_cache_update_execution_specI_intro
          with "Hseq Hcfg Hhist [] Hevidence").
        iPureIntro.
        exact Hnth.
      + iExact "Hstate'".
  Qed.

  Lemma pico_lr_cache_update_execution_specI_wp_bridge_after_execution
      `{!invGS Σ} `{!PicoIrisGhostState.picoCacheG Σ}
      E N N' sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
