  Lemma pico_lr_cache_update_tail_pool_interp :
    forall sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
           sigma threads i,
      cache_update_sequence_safe
        CT sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n ->
      nth_error
        threads
        i =
        Some
          (mkWMThread
            rΓ
            (cache_update_sequence_stmt tmp receiver cache_f n)
            Vthread) ->
      let tail_threads :=
        update
          i
          (mkWMThread
            (set_vars rΓ (update tmp (Int n) (vars rΓ)))
            (SFldWrite receiver cache_f tmp)
            Vthread)
          threads in
      pico_lr_config_interp
        (loc, cache_f)
        derived
        abs_vals
        (mkWMConfig sigma threads) ->
      pico_lr_config_interp
        (loc, cache_f)
        derived
        abs_vals
        (mkWMConfig sigma tail_threads).
  Proof.
    intros sΓ mt rΓ loc cache_f receiver tmp derived abs_vals n Vthread
           sigma threads i Hsafe Hnth tail_threads Hinterp.
    unfold pico_lr_config_interp in *.
    subst tail_threads.
    eapply cache_update_sequence_safe_update_threads_sem_typed; eauto.
    apply nth_error_Some.
    rewrite Hnth.
    discriminate.
  Qed.

